import { PropsWithChildren, useMemo } from 'react';

import { TOOLTIP_WRAPPER_PADDING } from '../constants.js';
import { TooltipDimensionsContext } from '../contexts/TooltipDimensionsContext.js';

export const TooltipContainerDimensionProvider = ({
  children,
  container,
}: PropsWithChildren<{ container: HTMLDivElement | null }>) => {
  const value = useMemo(() => {
    if (!container) {
      return null;
    }

    const padding = TOOLTIP_WRAPPER_PADDING * 2;

    return {
      width: container.clientWidth - padding,
      height: container.clientHeight,
    };
  }, [container]);

  return (
    <TooltipDimensionsContext.Provider value={value}>
      {children}
    </TooltipDimensionsContext.Provider>
  );
};
